import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';

const AiPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const messagesEndRef = useRef(null);
  
  // System prompt based on the current lesson
  const systemPrompts = {
    1: "You are a cybersecurity expert teaching password security best practices. Explain concepts simply with emojis and examples for young learners.",
    2: "You are a phishing awareness specialist. Help users identify suspicious emails with clear examples and warnings.",
    3: "You are a mobile security consultant. Teach best practices for securing smartphones against theft and malware.",
    4: "You are a social media privacy expert. Guide users on safe sharing practices and privacy settings.",
    5: "You are a web security professional. Explain how to identify secure websites and avoid download scams."
  };

  const systemPrompt = systemPrompts[id] || "You are a helpful cybersecurity assistant.";

  // Lesson data
  const lessons = {
    1: {
      title: "密码安全",
      description: "学习创建和管理强密码的最佳实践",
      icon: "🔐"
    },
    2: {
      title: "钓鱼攻击",
      description: "识别和防范网络钓鱼攻击",
      icon: "🎣"
    },
    3: {
      title: "移动安全",
      description: "保护移动设备免受威胁",
      icon: "📱"
    },
    4: {
      title: "社交媒体隐私",
      description: "管理您的社交媒体隐私设置",
      icon: "👥"
    },
    5: {
      title: "网页安全",
      description: "安全浏览网页和下载内容",
      icon: "🌐"
    }
  };

  // Initial welcome message based on lesson
  useEffect(() => {
    const welcomeMessages = {
      1: "你好！我是密码安全助手。问我任何关于创建强密码、双重认证或密码管理器的问题！🔐",
      2: "你好！我是钓鱼攻击检测助手。向我展示可疑邮件或询问如何识别诈骗！🎣",
      3: "你好！我是移动安全指南。询问关于手机锁屏、应用安全或防盗的问题！📱",
      4: "欢迎！我是社交媒体隐私教练。询问关于安全分享、好友列表或工作政策的问题！👥",
      5: "你好！我是网页安全顾问。询问关于安全网站、URL检查或安全下载的问题！🌐"
    };
    
    setMessages([{ role: 'assistant', content: welcomeMessages[id] || "你好！我是网络安全助手。今天有什么可以帮您的？" }]);
  }, [id]);

  // Auto-scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage = { role: 'user', content: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      const response = await fetch('https://dashscope.aliyuncs.com/compatible-mode/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${process.env.REACT_APP_ALIYUN_KEY}`,
        },
        body: JSON.stringify({
          model: 'qwen-turbo',
          messages: [
            { role: 'system', content: systemPrompt },
            ...messages.slice(-6),
            userMessage
          ]
        })
      });

      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      
      const data = await response.json();
      const aiResponse = data.choices?.[0]?.message?.content || "无法处理您的请求，请重试。";
      
      setMessages(prev => [...prev, { role: 'assistant', content: aiResponse }]);
    } catch (error) {
      console.error('API Error:', error);
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: "抱歉，连接AI服务时出现问题，请稍后再试。"
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const toggleMobileMenu = () => {
    setIsMobileMenuOpen(!isMobileMenuOpen);
  };

  return (
    <div style={styles.container}>
      {/* 移动端菜单按钮 */}
      <button 
        style={styles.mobileMenuButton}
        onClick={toggleMobileMenu}
      >
        {isMobileMenuOpen ? '×' : '☰'}
      </button>
      
      {/* 侧边栏导航 */}
      <div 
        style={{
          ...styles.sidebar,
          transform: window.innerWidth <= 768 ? 
            (isMobileMenuOpen ? 'translateX(0)' : 'translateX(-100%)') : 'none'
        }}
      >
        <h2 style={styles.sidebarTitle}>网络安全课程</h2>
        <div style={styles.sidebarMenu}>
          {Object.entries(lessons).map(([lessonId, lesson]) => (
            <div
              key={lessonId}
              style={{
                ...styles.menuItem,
                ...(id === lessonId ? styles.activeMenuItem : {})
              }}
              onClick={() => {
                navigate(`/ai/${lessonId}`);
                if (window.innerWidth <= 768) setIsMobileMenuOpen(false);
              }}
            >
              <span style={styles.menuIcon}>{lesson.icon}</span>
              <div style={styles.menuText}>
                <div style={styles.menuTitle}>课程 {lessonId}: {lesson.title}</div>
                <div style={styles.menuDescription}>{lesson.description}</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* 主内容区域 */}
      <div style={styles.mainContent}>
        <div style={styles.header}>
          <h1 style={styles.lessonTitle}>
            {lessons[id].icon} 课程 {id}: {lessons[id].title}
          </h1>
          <p style={styles.lessonDescription}>{lessons[id].description}</p>
        </div>
        
        <div style={styles.chatContainer}>
          <div style={styles.messages}>
            {messages.map((msg, index) => (
              <div 
                key={index} 
                style={msg.role === 'user' ? styles.userMessage : styles.assistantMessage}
              >
                <div style={styles.messageContent}>
                  {msg.role === 'assistant' && (
                    <div style={styles.assistantAvatar}>🤖</div>
                  )}
                  <div style={msg.role === 'assistant' ? styles.assistantText : styles.userText}>
                    {msg.content.split('\n').map((line, i) => (
                      <React.Fragment key={i}>
                        {line}
                        <br />
                      </React.Fragment>
                    ))}
                  </div>
                </div>
              </div>
            ))}
            {isLoading && (
              <div style={styles.assistantMessage}>
                <div style={styles.messageContent}>
                  <div style={styles.assistantAvatar}>🤖</div>
                  <div style={styles.assistantText}>
                    <div style={styles.typingIndicator}>
                      <span>.</span><span>.</span><span>.</span>
                    </div>
                  </div>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          <form onSubmit={handleSubmit} style={styles.inputForm}>
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={`关于${lessons[id].title}，您有什么问题？`}
              style={styles.inputField}
              disabled={isLoading}
            />
            <button 
              type="submit" 
              style={styles.submitButton}
              disabled={isLoading}
            >
              {isLoading ? '发送中...' : '发送'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

