      backgroundColor: '#4fb3bf'
    }
  },
  menuIcon: {
    fontSize: '24px',
    marginRight: '15px',
    flexShrink: 0
  },
  menuText: {
    flex: 1
  },
  menuTitle: {
    fontWeight: '500',
    marginBottom: '3px'
  },
  menuDescription: {
    fontSize: '0.85em',
    opacity: 0.8
  },
  mainContent: {
    flex: 1,
    marginLeft: '280px',
    padding: '20px',
    '@media (max-width: 768px)': {
      marginLeft: '0',
      paddingTop: '60px'
    }
  },
  header: {
    marginBottom: '30px',
    paddingBottom: '20px',
